513:     protected static String generateFunctionName(Function function) {
514:         Class<? extends Function> functionClass = function.getClass();
515:         if (functionClass.isAnonymousClass()) {
516:             // getSimpleName returns an empty String for anonymous classes
517:             Type[] interfaces = functionClass.getInterfaces();
518:             if (interfaces.length == 0) {
519:                 // extends an existing class (like RichMapFunction)
520:                 Class<?> functionSuperClass = functionClass.getSuperclass();
521:                 return functionSuperClass.getSimpleName()
522:                         + functionClass
523:                                 .getName()
524:                                 .substring(functionClass.getEnclosingClass().getName().length());
525:             } else {
526:                 // implements a Function interface
527:                 Class<?> functionInterface = functionClass.getInterfaces()[0];
528:                 return functionInterface.getSimpleName()
529:                         + functionClass
530:                                 .getName()
531:                                 .substring(functionClass.getEnclosingClass().getName().length());
532:             }
533:         } else {
534:             return functionClass.getSimpleName();
535:         }
536:     }
